    const orbX = parseInt(root.style.left) || 0;
    const orbY = parseInt(root.style.top)  || 0;
    const alignLeft = orbX < pwin.innerWidth / 2;
    menu.style.left  = alignLeft ? '0' : 'auto';
    menu.style.right = alignLeft ? 'auto' : '0';
    const goUp = orbY > pwin.innerHeight / 2;
    if (goUp) {
      menu.style.top = 'auto'; menu.style.bottom = '58px';
      root.classList.add('open-up');
      menu.style.transformOrigin = alignLeft ? 'bottom left' : 'bottom right';
    } else {
      menu.style.top = '58px'; menu.style.bottom = 'auto';
      root.classList.remove('open-up');
      menu.style.transformOrigin = alignLeft ? 'top left' : 'top right';
    }
  }

  function toggle() {
    isOpen = !isOpen;
    if (isOpen) { updateMenuDirection(); syncAllToggleBtns(); }
    else { root.classList.remove('open-up'); }
    root.classList.toggle('open', isOpen);
  }
  function close() { isOpen = true; toggle(); }
  btnClose.addEventListener('click', e => { e.stopPropagation(); close(); });

  // ── 保存位置 ──────────────────────────────────────────────
  function savePos() {
    try {
      insertOrAssignVariables({
        orbV2_pos: JSON.stringify({ x: parseInt(root.style.left), y: parseInt(root.style.top) })
      }, { type: 'global' });
    } catch (_) {}
  }

  // ── 拖拽 ─────────────────────────────────────────────────
  let drag = false, ox = 0, oy = 0, moved = false;

  // PC：全屏遮罩防止事件被ST子元素拦截
  let dragMask = null;
  function createMask() {
    try {
      dragMask = pdoc.createElement('div');
      dragMask.style.cssText = 'position:fixed;inset:0;z-index:2147483646;cursor:grabbing;background:transparent;';
      pdoc.body.appendChild(dragMask);
    } catch(e) {}
  }
  function removeMask() { dragMask?.remove(); dragMask = null; }

  function startDrag(cx, cy) {
    drag = true; moved = false;
    const rect = root.getBoundingClientRect();
    ox = cx - rect.left;
    oy = cy - rect.top;
    root.style.transition = 'none';
    createMask();
  }
  function moveDrag(cx, cy) {
    if (!drag) return;
    moved = true;
    root.style.left = Math.max(4, Math.min(cx - ox, pwin.innerWidth  - 56)) + 'px';
    root.style.top  = Math.max(4, Math.min(cy - oy, pwin.innerHeight - 56)) + 'px';
  }
  function endDrag() {
    if (!drag) return;
    drag = false;
    root.style.transition = '';
    removeMask();
    if (moved) savePos();
  }

  // PC鼠标拖拽
  orb.addEventListener('mousedown', e => { startDrag(e.clientX, e.clientY); e.preventDefault(); });
  head.addEventListener('mousedown', e => {
    if (e.target.id === `${ID}-close`) return;
    startDrag(e.clientX, e.clientY); e.preventDefault();
  });
  pdoc.addEventListener('mousemove', e => moveDrag(e.clientX, e.clientY));
  pdoc.addEventListener('mouseup', () => endDrag());
  // 备用：也在parent监听，防止鼠标移出iframe
  try {
    parent.document.addEventListener('mousemove', e => moveDrag(e.clientX, e.clientY));
    parent.document.addEventListener('mouseup', () => endDrag());
  } catch(e) {}

  // 点击展开（PC鼠标）
  // touchend 已处理了移动端的 toggle，用标志位防止 click 重复触发
  let suppressNextClick = false;
  orb.addEventListener('click', e => {
    if (suppressNextClick) { suppressNextClick = false; return; }
    if (moved) { moved = false; return; }
    toggle();
  });

  // ── 移动端触摸拖拽 ────────────────────────────────────────
  // 核心原则：
  // 1. touchstart/touchmove/touchend 全部 passive:false，才能 preventDefault 阻止滚动
  // 2. 用位移距离区分「点击」和「拖拽」
  // 3. touchmove 绑在 pdoc 上（全局），防止手指移出 orb 后跟丢

  let touchId = null; // 追踪的触摸点ID，多点触控只跟第一个

  function getTouchById(touches, id) {
    for (let i = 0; i < touches.length; i++) {
      if (touches[i].identifier === touchId) return touches[i];
    }
    return null;
  }

  orb.addEventListener('touchstart', e => {
    if (touchId !== null) return; // 已在拖拽，忽略多余触点
    const t = e.changedTouches[0];
    touchId = t.identifier;
    startDrag(t.clientX, t.clientY);
    // 不 preventDefault，让浏览器仍能处理 tap 的 click 事件
  }, { passive: true });

  pdoc.addEventListener('touchmove', e => {
    if (!drag || touchId === null) return;
    const t = getTouchById(e.changedTouches, touchId) || e.changedTouches[0];
    moveDrag(t.clientX, t.clientY);
    // 只要在拖拽就阻止页面滚动
    if (moved) e.preventDefault();
  }, { passive: false });

  pdoc.addEventListener('touchend', e => {
    if (touchId === null) return;
    const t = getTouchById(e.changedTouches, touchId);
    if (!t) return;
    touchId = null;
    const wasMoved = moved;
    endDrag();
    if (!wasMoved) {
      suppressNextClick = true; // 阻止紧随其后的 click 事件再次 toggle
      toggle();
    }
  }, { passive: true });

  pdoc.addEventListener('touchcancel', e => {
    touchId = null;
    endDrag();
  }, { passive: true });

  // head 触摸拖拽（菜单顶栏）
  head.addEventListener('touchstart', e => {
    if (e.target.id === `${ID}-close`) return;
    if (touchId !== null) return;
    const t = e.changedTouches[0];
    touchId = t.identifier;
    startDrag(t.clientX, t.clientY);
  }, { passive: true });

  head.addEventListener('touchend', e => {
    if (touchId === null) return;
    const t = getTouchById(e.changedTouches, touchId);
    if (t) { touchId = null; endDrag(); }
  }, { passive: true });

  // ── 自动清理 ──────────────────────────────────────────────
  window.addEventListener('pagehide', () => {
    pdoc.getElementById(ID)?.remove();
    pdoc.getElementById(`${ID}-style`)?.remove();
  });
  window.addEventListener('unload', () => {
    pdoc.getElementById(ID)?.remove();
    pdoc.getElementById(`${ID}-style`)?.remove();
  });

}));
